mapper.insert:
/* ====== cmn.fileup.insertCmnFileUpldMgmtMst =========*/	
    INSERT INTO CMN_FILE_UPLD_MGMT_MST 
    (
	   	 USR_ID
	   , MENU_ID
	   , FILE_UPLD_DT
	   , FILE_NM
	   , FILE_DESC
	   , DUTY_NM
	   , FILE_URL
	   , FILE_SIZE
	   , DATA_CNT
	 ) 
	VALUES
	 ( 
	   	 #{SESSION_USER_ID}
	   , nvl(#{menuId},'*')
	   , sysdate
	   , #{FILE_NM}
	   , #{FILE_DESC}
	   , #{DUTY_NM}
	   , #{FILE_URL}
	   , #{FILE_SIZE}
	   , #{DATA_CNT}
	 )
